package flow_test

import (
	"math/rand"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/onflow/flow-go/model/cluster"
	"github.com/onflow/flow-go/model/flow"
	"github.com/onflow/flow-go/utils/unittest"
)

func TestDeterministicID(t *testing.T) {
	// run with environment variable (to allow seeding the global rng): GODEBUG=randseednop=0
	// expected values generated by running on master and copying the ID generated
	// once it was confirmed that the ID is being generated deterministically
	rand.Seed(20)
	tx := unittest.TransactionFixture().TransactionBody
	assert.Equal(t, "61fd1abba407163b716d467adc3da0c01230ddc720d84b6f51bfaa9e5d4637a8", tx.ID().String(), "TransactionBody ID")

	rand.Seed(20)
	coll := unittest.CollectionFixture(2)
	assert.Equal(t, "5802d9805034abcb0db1bf794a7ce1f734cd4615805495599bc60a9df5b141f9", coll.ID().String(), "Collection ID")

	rand.Seed(20)
	collg := unittest.CollectionGuaranteeFixture()
	assert.Equal(t, "0ad346f9e6923ab1d2f091785e9ca0ea15c7281ff4bd6f7e011584f186c383de", collg.ID().String(), "CollectionGuarantee ID")

	rand.Seed(20)
	blockID := unittest.IdentifierFixture()
	state := unittest.StateCommitmentFixture()
	chunk := unittest.ChunkFixture(blockID, 0, state)
	assert.Equal(t, "762fb5d42074856443f6de59defd8a81dda13d1225ef0a83b4a0faae46c79d1b", chunk.ID().String(), "Chunk ID")

	rand.Seed(20)
	resultApproval := unittest.ResultApprovalFixture()
	assert.Equal(t, "ca06df1cf4768dc4d3afbbd70e881ad083f4ca16d742e808f5b16bd598797281", resultApproval.ID().String(), "ResultApproval ID")

	rand.Seed(27)
	epochState := unittest.EpochStateFixture()
	epochState.PreviousEpochSetup.TargetEndTime = 1001
	epochState.MinEpochStateEntry.PreviousEpoch.SetupID = epochState.PreviousEpochSetup.ID()
	epochState.CurrentEpochSetup.TargetEndTime = 2001
	epochState.MinEpochStateEntry.CurrentEpoch.SetupID = epochState.CurrentEpochSetup.ID()
	assert.Equal(t, "52522a7cae667ac8bef57c58464e5613a582815efa3af76f2ebc6144ed556e55", epochState.MinEpochStateEntry.ID().String(), "MinEpochStateEntry ID")

	rand.Seed(28)
	events := unittest.EventsFixture(3)
	eventsMerkle, err := flow.EventsMerkleRootHash(events)
	require.NoError(t, err)
	assert.Equal(t, "c85a5b070b8dad73f59cc972dd37f45fa7bfbc61f03b38559c04a5790199f6d9", eventsMerkle.String(), "EventsMerkleRootHash")

	rand.Seed(29)
	seal := unittest.Seal.Fixture()
	assert.Equal(t, "1fafaaad6c20e53b23209fb0432c885a921ac1f20451e249bc3b95dd128d7d77", seal.ID().String(), "Seal ID")

	// note we also need a deterministic timestamp on various block headers
	rand.Seed(20)
	results := []*flow.ExecutionResult{
		unittest.ExecutionResultFixture(),
		unittest.ExecutionResultFixture(),
	}
	receipts := []*flow.ExecutionReceipt{
		unittest.ExecutionReceiptFixture(unittest.WithResult(results[0])),
		unittest.ExecutionReceiptFixture(unittest.WithResult(results[1])),
	}
	assert.Equal(t, "44c533bda36d85671835e31872b3c0a0ff51d18c23a06255d205b33f01f2d0b8", receipts[0].ID().String(), "ExecutionReceipt (with result) ID")
	payload := flow.Payload{
		Guarantees: nil,
		Seals:      unittest.BlockSealsFixture(3),
		Results:    results,
		//Receipts:   []*flow.ExecutionReceiptStub{receipts[0].Stub(), receipts[1].Stub()},
		Receipts:        []*flow.ExecutionReceiptMeta{receipts[0].Meta(), receipts[1].Meta()},
		ProtocolStateID: unittest.IdentifierFixture(),
	}
	payloadHash := payload.Hash()
	assert.Equal(t, "508dca011879cc6b79860a5dafb627012c7171b689b49dca0ad81592f25e5800", payloadHash.String(), "PayloadHash")

	// basic header ID tests
	emptyHeader := &flow.Header{}
	assert.Equal(t, "69faedc38ea4f2393add93c230dea9b96a9261ae46a210e7f4ca95102ae51b59", emptyHeader.ID().String(), "Basic Header ID")
	emptyHeader.PayloadHash = unittest.IdentifierFixture()
	assert.Equal(t, "863d5a41d562ad570a29e089fc02d6c5a5f03d7741a7f551e3e67dc2cefcdd8d", emptyHeader.ID().String(), "Basic Header ID")
	emptyHeader.ParentID = unittest.IdentifierFixture()
	assert.Equal(t, "ef71043080c4a55ed97d51cc9239b741d6b811e8c7bd8d85f212fdb425dbe2b5", emptyHeader.ID().String(), "Basic Header ID")
	emptyHeader.PayloadHash = flow.Identifier{}
	assert.Equal(t, "db46eee46821e5c1283c3f6448c960ef06f094f6b32f9c07416f0ca8ffae5e37", emptyHeader.ID().String(), "Basic Header ID")

	// full header ID test
	rand.Seed(30)
	parent := &flow.Header{}
	parent.ChainID = flow.Emulator
	parent.ParentID = unittest.IdentifierFixture()
	parent.Height = 11
	parent.View = 17
	assert.Equal(t, "3e4527a6bb1f170a93ce3c1709519ca79e24eaf640dd8f58565ad085677406a5", parent.ID().String(), "Parent Header ID")

	height := parent.Height + 1
	view := parent.View + 1 + uint64(rand.Intn(10)) // Intn returns [0, n)
	assert.Equal(t, uint64(19), view)
	header := &flow.Header{}
	header.ChainID = parent.ChainID
	header.ParentID = parent.ID()
	header.Height = height
	assert.Equal(t, "84a1fd4888c4686f6a1c4eea783e26a291c0dfb42376601f71317dcfb1e8a685", header.ID().String(), "Header ID: ChainID,ParentID,Height")
	header.Timestamp = time.Unix(1000, 0)
	header.View = view
	header.ParentView = parent.View
	assert.Equal(t, "6bde2dfe7644df624d0220410588e9cc7e060209f41575f39fc6a38cce2e32b3", header.ID().String(), "Header ID: Timestamp,View,ParentView")
	header.ParentVoterIndices = unittest.SignerIndicesFixture(4)
	assert.Equal(t, "446a1eaefbcd9002d29f985b7a0862f7031513820740742c0b565655c3d2b46c", header.ID().String(), "Header ID: ParentVoterIndices")
	header.ParentVoterSigData = unittest.QCSigDataFixture()
	assert.Equal(t, "573e4e66eb440a7545a57cae2bd9756f759f82aba95c76aa103bf885a5345ca9", header.ID().String(), "Header ID: QCSigData")
	header.ProposerID = unittest.IdentifierFixture()
	assert.Equal(t, "5b22c4988f518c186ce117ec4bad513c47693924e3282a108f4dfdea632f89ff", header.ID().String(), "Header ID: ProposerID")
	// no ProposerSigData
	header.PayloadHash = unittest.IdentifierFixture()
	assert.Equal(t, "39f8e6f10099352f086702cf322fcd1bbd5f7b5d278637ae0f7de3390803b02e", header.ID().String(), "Full Header ID")

	// TimeoutCert ID
	rand.Seed(35)
	newestQC := unittest.QuorumCertificateFixture(func(qc *flow.QuorumCertificate) {
		qc.View = parent.View
	})
	lastViewTC := &flow.TimeoutCertificate{
		View:          view - 1,
		NewestQCViews: []uint64{newestQC.View},
		NewestQC:      newestQC,
		SignerIndices: unittest.SignerIndicesFixture(4),
		SigData:       unittest.SignatureFixture(),
	}
	assert.Equal(t, "ec7791fa8b928cd140d5405ab9e7ce48e5b8e8c1ddfb8be13df9f758e5f9fc04", lastViewTC.ID().String(), "TimeoutCertificate ID")
	header.LastViewTC = lastViewTC
	assert.Equal(t, "a51aa50c98e78f19c55bcf6bdb9e63ab2d57a347d1255c5fde139bb368b18f76", header.ID().String(), "Header (with TC) ID")

	header.PayloadHash = payloadHash
	block := flow.Block{
		Header:  header,
		Payload: &payload,
	}
	assert.Equal(t, header.ID().String(), block.ID().String(), "Header ID = Block ID")
	assert.Equal(t, "0256b96a2007ab270dfea0f11b0180c1c434192bb80a3b531ee87172a1ec2a0c", block.ID().String(), "Block ID")

	clusterPayload := unittest.ClusterPayloadFixture(2)
	assert.Equal(t, "fab95481efd28bf31bd3f02d1fea2adac989f5dbe9411e55fca299324cdef029", clusterPayload.Hash().String(), "ClusterPayload Hash")
	header.PayloadHash = clusterPayload.Hash()
	clusterBlock := cluster.Block{
		Header:  header,
		Payload: clusterPayload,
	}
	assert.Equal(t, "4be6eb738d3e8989c9ce585b586b1d457c113cd55d9c4e1e4487ec6867b9653d", clusterBlock.ID().String(), "ClusterBlock ID")
}
